// Frontend (Example using Axios interceptor in client/src/api/axiosConfig.js)
import axios from 'axios';

const axiosInstance = axios.create({
  baseURL: 'https://coaileague.com/api',
  withCredentials: true, // Only if using cookies/sessions; remove if purely token-based
});

axiosInstance.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('authToken'); // Get token from storage
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

export default axiosInstance;

// Backend (Example for server/middleware/authMiddleware.js and server/routes/api/mascot.js)
// server/middleware/authMiddleware.js
import jwt from 'jsonwebtoken';
import 'dotenv/config'; // Ensure dotenv is configured

export const protect = (req, res, next) => {
  let token;

  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    try {
      token = req.headers.authorization.split(' ')[1];
      const decoded = jwt.verify(token, process.env.JWT_SECRET); // Verify token with secret
      // Optionally attach user to request object: req.user = await User.findById(decoded.id).select('-password');
      next(); // If token is valid, proceed to the next middleware/route handler
    } catch (error) {
      console.error('Authentication error:', error.message); // Log the specific error
      return res.status(401).json({ message: 'Not authorized, token failed or expired' });
    }
  }

  if (!token) {
    return res.status(401).json({ message: 'Not authorized, no token provided' });
  }
};

// server/routes/api/mascot.js
import express from 'express';
import { protect } from '../middleware/authMiddleware';
// import { getMascotState } from '../controllers/mascotController'; // Your actual controller function

const router = express.Router();

// Apply the 'protect' middleware to secure the route
router.get('/seasonal/state', protect, (req, res) => {
    // If we reach here, the token was successfully validated
    res.status(200).json({ state: 'Current seasonal mascot status' });
});

export default router;
